 18â†’// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
 19â†’export function createAuth(db: object, config: AuthConfig) {
 20â†’	const trustedOrigins = config.trustedOrigins ?? [];
 21â†’	if (!trustedOrigins.includes(config.appURL)) {
 22â†’		trustedOrigins.push(config.appURL);
 23â†’	}
 24â†’
 25â†’	return betterAuth({
 26â†’		baseURL: config.appURL,
 27â†’		secret: config.secret,
 28â†’		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
 29â†’			provider: "pg",
 30â†’			schema,
 31â†’		}),
 32â†’		emailAndPassword: {
 33â†’			enabled: true,
 34â†’		},
 35â†’		socialProviders: config.socialProviders,
 36â†’		plugins: [
 37â†’			bearer(),
 38â†’			organization({
 39â†’				allowUserToCreateOrganization: true,
 40â†’				creatorRole: "owner",
 41â†’			}),
 42â†’		],
 43â†’		session: {
 44â†’			expiresIn: 60 * 60 * 24 * 365,
 45â†’		},
 46â†’		trustedOrigins,
 47â†’		databaseHooks: {
 48â†’			user: {
 49â†’				create: {
 50â†’					after: async (user, ctx) => {
 51â†’						try {
 52â†’							const adapter = ctx?.context?.adapter;
 53â†’							if (!adapter) return;
 54â†’
 55â†’							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
 56â†’							const org = await adapter.create({
 57â†’								model: "organization",
 58â†’								data: {
 59â†’									id: user.id,
 60â†’									name: `${user.name}'s Workspace`,
 61â†’									slug,
 62â†’									createdAt: new Date(),
 63â†’								},
 64â†’								forceAllowId: true,
 65â†’							});
 66â†’
 67â†’							if (org) {
 68â†’								await adapter.create({
 69â†’									model: "member",
 70â†’									data: {
 71â†’										organizationId: org.id,
 72â†’										userId: user.id,
 73â†’										role: "owner",
 74â†’										createdAt: new Date(),
 75â†’									},
 76â†’								});
 77â†’							}
 78â†’
 79â†’							if (config.slackWebhookUrl) {
 80â†’								let githubHandle: string | null = null;
 81â†’								const accounts = (await adapter.findMany({
 82â†’									model: "account",
 83â†’									where: [{ field: "userId", value: user.id }],
 84â†’								})) as Array<{ providerId: string; accountId: string }>;
 85â†’								const githubAccount = accounts.find(
 86â†’									(a) => a.providerId === "github",
 87â†’								);
 88â†’								if (githubAccount) {
 89â†’									githubHandle = await fetchGitHubHandle(
 90â†’										githubAccount.accountId,
 91â†’									);
 92â†’								}
 93â†’								await notifySignup(
 94â†’									config.slackWebhookUrl,
 95â†’									{ name: user.name, email: user.email },
 96â†’									githubHandle,
 97â†’								);
 98â†’							}
 99â†’						} catch (err) {
100â†’							logger.error(
101â†’								"Failed to create default organization for user {userId}: {error}",
102â†’								{ userId: user.id, error: err },
103â†’							);
104â†’						}
105â†’					},
106â†’				},
107â†’			},
108â†’		},
109â†’	});
110â†’}
